      $$<table style="border-collapse:collapse;border-spacing:0;margin:0;padding:0;width:100%;background:#ffffff;font-family:Arial,'Helvetica Neue',Helvetica,sans-serif;color:#333333;" cellpadding="0" cellspacing="0" width="100%"><tbody><tr><td align="center"><table style="border-collapse:collapse;border-spacing:0;background:#ffffff;width:600px;max-width:100%;" cellpadding="0" cellspacing="0" width="600"><tbody><tr><td style="padding:20px 20px 0;" align="center"><img width="220" style="display:block;border:0;max-width:220px;width:100%;height:auto;" alt="Oyabun Tattoo" src="https://jviaxe.stripocdn.email/content/guids/CABINET_6a3bfa96617ed85bcc5a755c7e8d8864/images/logo_trans.png"></td></tr><tr><td style="padding:20px 20px 25px;" align="center"><table style="border-collapse:separate;border-spacing:0;border:3px solid #ffc600;border-radius:20px;width:100%;" cellpadding="0" cellspacing="0" width="100%"><tbody><tr><td style="height:26px;">&nbsp;</td></tr><tr><td style="padding:0 38px;" align="center"><h1 style="margin:0;font-size:28px;line-height:1.25;color:#333333;font-weight:700;">Your appointment has been cancelled</h1></td></tr><tr><td style="padding:12px 38px 0;" align="center"><p style="margin:0;font-size:18px;line-height:1.45;color:#333333;"><em>Reply to this email if you have questions or need to reschedule.</em></p></td></tr><tr><td style="padding:24px 38px 0;text-align:left;font-size:16px;line-height:1.55;color:#333333;"><p style="margin:0 0 14px;">Hi {{customerName}},</p><p style="margin:0 0 14px;">Your tattoo appointment has been cancelled.</p><p style="margin:0;"><strong>Project:</strong> {{projectName}}<br><strong>Artist:</strong> {{artistName}}<br><strong>Original appointment:</strong> {{appointmentTime}}</p></td></tr><tr><td style="height:30px;">&nbsp;</td></tr></tbody></table></td></tr></tbody></table></td></tr></tbody></table>$$,
